import { useState } from 'react';
import { Card, Stack, Row, Text } from '@ggui-ai/design/primitives';

interface ForecastDay {
  day: string;
  icon: string;
  high: number;
  low: number;
}

interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit: string;
  forecast: ForecastDay[];
}

export default function GeneratedComponent({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit,
  forecast,
}: Props) {
  return (
    <Card padding="var(--ggui-spacing-6, 24px)" shadow="md">
      <Stack direction="vertical" gap={24} align="stretch">
        {/* Header with City */}
        <Text
          variant="h2"
          color="var(--ggui-color-onSurface, #18181b)"
          weight="bold"
        >
          {city}
        </Text>

        {/* Current Weather Section */}
        <Stack direction="horizontal" gap={32} align="center">
          {/* Temperature and Icon */}
          <Stack direction="vertical" gap={16} align="center">
            {/* Large Temperature */}
            <div
              style={{
                fontSize: 'var(--ggui-font-size-4xl, 36px)',
                fontWeight: 'var(--ggui-font-weight-bold, 700)',
                color: 'var(--ggui-color-primary-600, #0284c7)',
                lineHeight: '1',
              }}
            >
              {Math.round(temperature)}°{unit}
            </div>

            {/* Weather Icon and Condition */}
            <Stack direction="vertical" gap={8} align="center">
              <div
                style={{
                  fontSize: '48px',
                  lineHeight: '1',
                  textAlign: 'center',
                }}
              >
                {condition}
              </div>
              <Text
                variant="body"
                color="var(--ggui-color-onSurfaceVariant, #52525b)"
                align="center"
                weight="medium"
              >
                {condition === '☀️' && 'Sunny'}
                {condition === '☁️' && 'Cloudy'}
                {condition === '🌧️' && 'Rainy'}
                {condition === '⛈️' && 'Stormy'}
                {condition === '🌫️' && 'Foggy'}
                {condition === '❄️' && 'Snowy'}
                {!['☀️', '☁️', '🌧️', '⛈️', '🌫️', '❄️'].includes(condition) && condition}
              </Text>
            </Stack>
          </Stack>

          {/* Humidity and Wind Speed */}
          <Stack direction="vertical" gap={20} align="stretch">
            {/* Humidity Card */}
            <div
              style={{
                backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                padding: 'var(--ggui-spacing-4, 16px)',
                border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack direction="vertical" gap={8}>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  Humidity
                </Text>
                <div
                  style={{
                    fontSize: 'var(--ggui-font-size-2xl, 24px)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                  }}
                >
                  {humidity}%
                </div>
              </Stack>
            </div>

            {/* Wind Speed Card */}
            <div
              style={{
                backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                padding: 'var(--ggui-spacing-4, 16px)',
                border: '1px solid var(--ggui-color-outline, #d4d4d8)',
              }}
            >
              <Stack direction="vertical" gap={8}>
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  Wind Speed
                </Text>
                <div
                  style={{
                    fontSize: 'var(--ggui-font-size-2xl, 24px)',
                    fontWeight: 'var(--ggui-font-weight-semibold, 600)',
                    color: 'var(--ggui-color-onSurface, #18181b)',
                  }}
                >
                  {Math.round(windSpeed)} {unit === 'F' ? 'mph' : 'km/h'}
                </div>
              </Stack>
            </div>
          </Stack>
        </Stack>

        {/* Divider */}
        <div
          style={{
            height: '1px',
            backgroundColor: 'var(--ggui-color-outline, #d4d4d8)',
          }}
        />

        {/* 5-Day Forecast */}
        <Stack direction="vertical" gap={12}>
          <Text
            variant="label"
            color="var(--ggui-color-onSurface, #18181b)"
            weight="semibold"
          >
            5-Day Forecast
          </Text>

          <Row gap={8} justify="between" wrap>
            {forecast.map((day, index) => (
              <div
                key={index}
                style={{
                  flex: '1 1 calc(20% - var(--ggui-spacing-2, 8px))',
                  minWidth: '100px',
                  backgroundColor: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
                  borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                  padding: 'var(--ggui-spacing-3, 12px)',
                  border: '1px solid var(--ggui-color-outline, #d4d4d8)',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  gap: 'var(--ggui-spacing-2, 8px)',
                  textAlign: 'center',
                }}
              >
                {/* Day Name */}
                <Text
                  variant="caption"
                  color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  weight="medium"
                >
                  {day.day}
                </Text>

                {/* Weather Icon */}
                <div style={{ fontSize: '24px', lineHeight: '1' }}>
                  {day.icon}
                </div>

                {/* High/Low Temps */}
                <Stack direction="horizontal" gap={4} justify="center">
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurface, #18181b)"
                    weight="semibold"
                  >
                    {Math.round(day.high)}°
                  </Text>
                  <Text
                    variant="caption"
                    color="var(--ggui-color-onSurfaceVariant, #52525b)"
                  >
                    {Math.round(day.low)}°
                  </Text>
                </Stack>
              </div>
            ))}
          </Row>
        </Stack>
      </Stack>
    </Card>
  );
}
